import java.io.*;

public class ByteStreamDemo {
    public static void main(String[] args) {
        System.out.println("=== Byte Streams Demonstration ===\n");

        // Write bytes to file
        try (FileOutputStream fos = new FileOutputStream("data.bin")) {
            byte[] data = {10, 20, 30, 40, 50};
            fos.write(data);
            System.out.println("Data written: " + java.util.Arrays.toString(data));
        } catch (IOException e) {
            System.err.println("Error writing: " + e.getMessage());
        }

        // Read bytes from file
        try (FileInputStream fis = new FileInputStream("data.bin")) {
            System.out.println("\nReading bytes:");
            int b;
            while ((b = fis.read()) != -1) {
                System.out.print(b + " ");
            }
            System.out.println();
        } catch (IOException e) {
            System.err.println("Error reading: " + e.getMessage());
        }

        // Copy file
        try {
            copyFile("data.bin", "data_copy.bin");
            System.out.println("\nFile copied successfully");
        } catch (IOException e) {
            System.err.println("Error copying: " + e.getMessage());
        }

        // Write with DataOutputStream
        System.out.println("\n=== DataOutputStream ===");
        try (DataOutputStream dos = new DataOutputStream(
                new FileOutputStream("data.dat"))) {
            dos.writeInt(100);
            dos.writeDouble(3.14);
            dos.writeUTF("Hello Java");
            System.out.println("Primitive data written");
        } catch (IOException e) {
            System.err.println("Error: " + e.getMessage());
        }

        // Read with DataInputStream
        System.out.println("\n=== DataInputStream ===");
        try (DataInputStream dis = new DataInputStream(
                new FileInputStream("data.dat"))) {
            int i = dis.readInt();
            double d = dis.readDouble();
            String s = dis.readUTF();
            System.out.println("Read: " + i + ", " + d + ", " + s);
        } catch (IOException e) {
            System.err.println("Error: " + e.getMessage());
        }
    }

    public static void copyFile(String source, String dest) throws IOException {
        try (FileInputStream fis = new FileInputStream(source);
             FileOutputStream fos = new FileOutputStream(dest)) {
            byte[] buffer = new byte[1024];
            int bytesRead;
            while ((bytesRead = fis.read(buffer)) != -1) {
                fos.write(buffer, 0, bytesRead);
            }
        }
    }
}

import java.io.*;

public class CharacterStreamDemo {
    public static void main(String[] args) {
        System.out.println("=== Character Streams Demonstration ===\n");

        // Write to file
        try (FileWriter fw = new FileWriter("text.txt")) {
            String content = "Hello, Java!\nThis is a text file.\nCharacter streams are used for text.";
            fw.write(content);
            System.out.println("Text written to file");
        } catch (IOException e) {
            System.err.println("Error writing: " + e.getMessage());
        }

        // Read from file
        System.out.println("\n=== Reading Text File ===");
        try (FileReader fr = new FileReader("text.txt")) {
            int ch;
            System.out.print("File content: ");
            while ((ch = fr.read()) != -1) {
                System.out.print((char) ch);
            }
            System.out.println();
        } catch (IOException e) {
            System.err.println("Error reading: " + e.getMessage());
        }

        // Read with character array
        System.out.println("\n=== Reading with Character Array ===");
        try (FileReader fr = new FileReader("text.txt")) {
            char[] buffer = new char[50];
            int charsRead = fr.read(buffer);
            System.out.print("Buffer: ");
            for (int i = 0; i < charsRead; i++) {
                System.out.print(buffer[i]);
            }
            System.out.println();
        } catch (IOException e) {
            System.err.println("Error: " + e.getMessage());
        }

        // Append to file
        System.out.println("\n=== Appending to File ===");
        try (FileWriter fw = new FileWriter("text.txt", true)) {
            fw.write("\nThis line is appended!");
            System.out.println("Text appended");
        } catch (IOException e) {
            System.err.println("Error: " + e.getMessage());
        }

        // Read appended file
        System.out.println("\n=== Reading Appended File ===");
        try (FileReader fr = new FileReader("text.txt")) {
            System.out.print("File content: ");
            int ch;
            while ((ch = fr.read()) != -1) {
                System.out.print((char) ch);
            }
            System.out.println();
        } catch (IOException e) {
            System.err.println("Error: " + e.getMessage());
        }
    }
}

import java.io.*;

public class BufferedReaderDemo {
    public static void main(String[] args) {
        System.out.println("=== BufferedReader and BufferedWriter ===\n");

        // Write with BufferedWriter
        try (BufferedWriter writer = new BufferedWriter(
                new FileWriter("buffered.txt"))) {
            writer.write("First line");
            writer.newLine();
            writer.write("Second line");
            writer.newLine();
            writer.write("Third line");
            writer.newLine();
            System.out.println("File written with BufferedWriter");
        } catch (IOException e) {
            System.err.println("Error: " + e.getMessage());
        }

        // Read with BufferedReader
        System.out.println("\n=== Reading with BufferedReader ===");
        try (BufferedReader reader = new BufferedReader(
                new FileReader("buffered.txt"))) {
            String line;
            int lineNum = 1;
            while ((line = reader.readLine()) != null) {
                System.out.println("Line " + lineNum + ": " + line);
                lineNum++;
            }
        } catch (IOException e) {
            System.err.println("Error: " + e.getMessage());
        }

        // Reading from keyboard
        System.out.println("\n=== Reading from Keyboard ===");
        try (BufferedReader reader = new BufferedReader(
                new InputStreamReader(System.in))) {
            System.out.print("Enter your name: ");
            String name = reader.readLine();
            System.out.println("Hello, " + name + "!");

            System.out.print("Enter your age: ");
            String ageStr = reader.readLine();
            int age = Integer.parseInt(ageStr);
            System.out.println("You are " + age + " years old");
        } catch (IOException e) {
            System.err.println("Error: " + e.getMessage());
        }

        // Copy file with buffered streams
        System.out.println("\n=== Copying File with Buffered Streams ===");
        try (BufferedReader reader = new BufferedReader(
                new FileReader("buffered.txt"));
             BufferedWriter writer = new BufferedWriter(
                new FileWriter("buffered_copy.txt"))) {
            String line;
            while ((line = reader.readLine()) != null) {
                writer.write(line);
                writer.newLine();
            }
            System.out.println("File copied successfully");
        } catch (IOException e) {
            System.err.println("Error: " + e.getMessage());
        }

        // Mark and reset
        System.out.println("\n=== Mark and Reset ===");
        try (BufferedReader reader = new BufferedReader(
                new FileReader("buffered.txt"))) {
            // Mark position
            reader.mark(100);
            System.out.println("Line 1: " + reader.readLine());
            System.out.println("Line 2: " + reader.readLine());
            reader.reset();  // Go back to marked position
            System.out.println("After reset - Line 1: " + reader.readLine());
        } catch (IOException e) {
            System.err.println("Error: " + e.getMessage());
        }
    }
}

